T_dew = 283.15

# Find defrost time for each p (first time T_min >= T_dew), in minutes
p_values = []
defrost_times = []

for p in sorted(data.keys()):
    times = sorted(data[p].keys())
    defrost_t = None
    for t in times:
        if data[p][t] >= T_dew:
            defrost_t = t / 60.0  # convert to minutes
            break
    p_values.append(p)
    if defrost_t is not None:
        defrost_times.append(defrost_t)
    else:
        defrost_times.append(None)

# Separate into defrost and never-defrost
p_defrost = [p for p, t in zip(p_values, defrost_times) if t is not None]
t_defrost = [t for t in defrost_times if t is not None]

fig, ax = plt.subplots(figsize=(7, 4.5))

ax.plot(p_defrost, t_defrost, 's-', color='#2c3e50', markerfacecolor='#2c3e50',
        markeredgecolor='#2c3e50', markersize=4, linewidth=1.4,
        label='Defrost time')

# Highlight optimum at p=1.3
opt_idx = p_defrost.index(1.3)
ax.plot(p_defrost[opt_idx], t_defrost[opt_idx], 'D', color='#c0392b',
        markersize=7, zorder=5, markeredgecolor='#c0392b',
        label=f'Optimum: $p = 1.3$, $t_{{\\mathrm{{defrost}}}} = {t_defrost[opt_idx]:.0f}$ min')

# Mark p=0.7 as "Never"
if 0.70 in [p for p, t in zip(p_values, defrost_times) if t is None]:
    ax.annotate('Never', xy=(0.70, max(t_defrost) + 2), fontsize=9,
                ha='center', color='#c0392b', fontweight='bold')

ax.set_xlabel('Chebyshev exponent $p$', fontsize=12)
ax.set_ylabel('Defrost time (min)', fontsize=12)
ax.legend(fontsize=9.5, loc='upper right', framealpha=0.9, edgecolor='#cccccc')
ax.grid(True, which='both', linestyle='-', alpha=0.35)
ax.minorticks_on()
ax.grid(True, which='minor', linestyle=':', alpha=0.2)
ax.set_xlim(0.6, 2.0)
ax.tick_params(labelsize=10)

plt.tight_layout()
